const APP_ID = $env.ADZUNA_APP_ID; const APP_KEY = $env.ADZUNA_APP_KEY;
const bassins = [
  { where: 'Rennes', distance: 80, bassin: 'Grande Région Rennes', assigne: 'Laurène' },
  { where: 'Nantes', distance: 80, bassin: 'Grande Région Nantes', assigne: 'Adrien' }
];
const PAGES = 3, MAX_DAYS_OLD = 2, DEPTS_OK = ['35','56','22','29','44','49','85'];
const NAF_ESN = ['62.01Z','62.02A','62.02B','62.03Z','62.09Z','70.22Z'], NAF_RECRUT = ['78.10Z','78.20Z','78.30Z'];
const EXCLUSION_SHODO = [];
function stacks(t) { t = (t||'').toLowerCase(); const o = []; if(/java/.test(t)) o.push('Java'); if(/\.net|c#/.test(t)) o.push('.NET'); if(/python/.test(t)) o.push('Python'); if(/data/.test(t)) o.push('Data'); if(/\bia\b|machine learning|\bml\b|llm/.test(t)) o.push('IA / ML'); if(/devops|docker|kubernetes/.test(t)) o.push('DevOps'); if(/architect/.test(t)) o.push('Architecture'); if(/chef de projet|product owner|scrum/.test(t)) o.push('Chef de projet'); if(/cloud|aws|azure|gcp/.test(t)) o.push('Cloud'); if(/mobile|android|ios|flutter/.test(t)) o.push('Mobile'); if(/front|react|angular|vue/.test(t)) o.push('Front'); return o.length ? o : ['Autre']; }
const http = this.helpers.httpRequest, out = [];
for (const b of bassins) {
  for (let i = 0; i !== PAGES; i++) {
    let res; try { res = await http({ method: 'GET', url: 'https://api.adzuna.com/v1/api/jobs/fr/search/' + (i+1), qs: { app_id: APP_ID, app_key: APP_KEY, where: b.where, distance: b.distance, category: 'it-jobs', max_days_old: MAX_DAYS_OLD, results_per_page: 50, sort_by: 'date' }, json: true }); } catch (e) { continue; }
    for (const job of (res.results || [])) {
      const company = ((job.company && job.company.display_name) || '').trim();
      if (!company) continue;
      let skip = false; for (const c of EXCLUSION_SHODO) { if (company.toLowerCase().indexOf(c.toLowerCase()) !== -1) skip = true; }
      if (skip) continue;
      let siren = '', naf = '', ville = (job.location && job.location.display_name) || '', cp = '';
      try { const ent = await http({ method: 'GET', url: 'https://recherche-entreprises.api.gouv.fr/search', qs: { q: company, per_page: 1 }, json: true }); const e = ent.results && ent.results[0]; if (e) { siren = e.siren || ''; naf = (e.siege && e.siege.activite_principale) || ''; ville = (e.siege && e.siege.libelle_commune) || ville; cp = (e.siege && e.siege.code_postal) || ''; } } catch (e) {}
      let type = 'Client final'; if (NAF_ESN.indexOf(naf) !== -1) type = 'ESN'; else if (NAF_RECRUT.indexOf(naf) !== -1) type = 'Cabinet recrutement'; else if (!naf) type = 'Inconnu';
      if (type === 'ESN' || type === 'Cabinet recrutement') continue;
      let dept = cp ? cp.substring(0,2) : ''; if (DEPTS_OK.indexOf(dept) === -1) dept = 'Autre';
      const dateSignal = (job.created || '').substring(0,10);
      out.push({ json: { 'Entreprise': company, 'SIREN / SIRET': siren, 'Code NAF': naf, 'Type entreprise': type, 'Ville': ville, 'Département': dept, 'Bassin': b.bassin, 'Assigné à': b.assigne, "Signal d'achat": job.title + ' - ' + b.where + ' (Adzuna)', 'Intitulé(s) de poste': job.title || '', 'Profils / Stack': stacks(job.title), 'Date du signal': dateSignal, 'Source': 'Adzuna', 'Lien offre': job.redirect_url || '' } });
    }
  }
}
const seen = new Set(); const dedup = [];
for (const o of out) { const k = (o.json.Entreprise || '').toLowerCase(); if (!k || seen.has(k)) continue; seen.add(k); dedup.push(o); }
return dedup;

const items = $input.all(); const http = this.helpers.httpRequest; const GKEY = $env.GEMINI_API_KEY; const cache = new Map(); const out = [];
const clean = n => (n || '').replace(/\s*\([^)]*\)\s*/g, ' ').replace(/—.*$/, '').replace(/\s+/g, ' ').trim();
const BATCH_SIZE = 10;
const batch = items.slice(0, BATCH_SIZE);
for (const it of batch) {
  const f = it.json; const id = f.id; const fields = f.fields || f; const company = (fields.Entreprise || '').toString().trim();
  if (!company || !id) continue;
  const c = clean(company); let url = '';
  if (cache.has(c)) { url = cache.get(c); } else {
    try {
      if (GKEY) {
        const prompt = "Quelle est l'URL exacte de la page LinkedIn officielle de l'entreprise « " + c + " » en France ? Réponds UNIQUEMENT par l'URL au format https://www.linkedin.com/company/... Si tu n'es pas certain à 100%, réponds exactement: AUCUNE. Aucun autre texte.";
        const r = await http({ method: 'POST', url: 'https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent?key=' + encodeURIComponent(GKEY), body: { contents: [{ parts: [{ text: prompt }] }], tools: [{ google_search: {} }], generationConfig: { temperature: 0 } }, json: true, timeout: 10000 });
        const parts = (r && r.candidates && r.candidates[0] && r.candidates[0].content && r.candidates[0].content.parts) || [];
        const txt = parts.map(p => p.text || '').join(' ');
        const m = txt.match(/https?:\/\/[a-z.]*linkedin\.com\/company\/[^\s)]+/i);
        if (m) url = m[0].replace(/[).,]+$/, '').replace(/\/$/, '');
      }
    } catch (e) { url = ''; }
    cache.set(c, url);
  }
  if (url) out.push({ json: { id: id, 'Page LinkedIn entreprise': url } });
}
return out;
